<?php
class VideoController { public function watch(string $slug): void { $m=new Video(); $v=$m->findBySlug($slug); if(!$v){http_response_code(404); View::render('errors/404',['title'=>'Not found']); return;} $m->incrementView((int)$v['id']); View::render('watch',['title'=>$v['title'],'video'=>$v]); }
 public function upload(): void { if(empty($_SESSION['user_id'])) { header('Location: /login'); exit; } if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){ Security::verifyCsrf(); $cfg=App::config('uploads'); Security::validateUpload($_FILES['video'],$cfg['allowed_video'],$cfg['video_max_mb']); if(!empty($_FILES['thumbnail']['tmp_name'])) Security::validateUpload($_FILES['thumbnail'],$cfg['allowed_image'],$cfg['image_max_mb']); $db=App::get('db'); $ch=$db->prepare('SELECT id FROM channels WHERE user_id=?'); $ch->execute([$_SESSION['user_id']]); $channel=(int)$ch->fetchColumn(); $slug=Validator::slug($_POST['title']).'-'.bin2hex(random_bytes(3)); $videoName=$slug.'.'.pathinfo($_FILES['video']['name'],PATHINFO_EXTENSION); move_uploaded_file($_FILES['video']['tmp_name'], BASE_PATH.'/videos/'.$videoName); $thumb=null; if(!empty($_FILES['thumbnail']['tmp_name'])){$thumb=$slug.'.'.pathinfo($_FILES['thumbnail']['name'],PATHINFO_EXTENSION); move_uploaded_file($_FILES['thumbnail']['tmp_name'], BASE_PATH.'/thumbnails/'.$thumb);} $s=$db->prepare('INSERT INTO videos(channel_id,title,slug,description,tags,category_id,video_path,thumbnail_path,visibility,status,published_at,allow_download,allow_embed,age_restricted,created_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW())'); $s->execute([$channel,Validator::str($_POST['title'],3,180),$slug,trim($_POST['description']??''),trim($_POST['tags']??''),$_POST['category_id']?:null,'/videos/'.$videoName,$thumb?'/thumbnails/'.$thumb:null,$_POST['visibility']??'public',$_POST['status']??'published',$_POST['published_at']?:null,!empty($_POST['allow_download']),!empty($_POST['allow_embed']),!empty($_POST['age_restricted'])]); Audit::log('video_upload',['slug'=>$slug]); header('Location: /watch/'.$slug); exit; } View::render('upload',['title'=>'Upload']); }}
